const userInputItems = $('INFLUENCER: CHECK MODE').all();
const previousNodeItems = $input.all();

// ── Extract data ──────────────────────────────────────────────────────────────
const userInput = userInputItems[0].json;
const entries = userInput.entries || [];
const newEntry = entries[0]; // single submission mode
const newsletterName = newEntry.placementType;

// ── Placement limits ──────────────────────────────────────────────────────────
const LIMITS = {
  'Featured': 1,
  'Featured Demo': 1,
  'Promoted': 6,
  'Standard': 6,
};
const MAX_TOTAL = 13;

// ── Parse existing bookings ───────────────────────────────────────────────────
const isEmpty =
  previousNodeItems.length === 0 ||
  (previousNodeItems.length === 1 && Object.keys(previousNodeItems[0].json).length === 0);

const existingBookings = isEmpty
  ? []
  : previousNodeItems.map(item => item.json);

// ── Filter existing bookings matching the new entry's placement type ───────────
const matchedBookings = existingBookings.filter(
  b => b.newsletter_placement === newEntry.placementType
);

// ── Count existing placements ─────────────────────────────────────────────────
const placementCounts = {
  'Featured': 0,
  'Featured Demo': 0,
  'Promoted': 0,
  'Standard': 0,
};

for (const booking of existingBookings) {
  const p = booking.newsletter_placement;
  if (p in placementCounts) placementCounts[p]++;
}

// ── Apply Featured Demo rule: reduces Standard max from 6 → 5 ────────────────
const hasFeaturedDemo =
  placementCounts['Featured Demo'] > 0 ||
  newEntry.placementType === 'Featured Demo';

const effectiveLimits = { ...LIMITS };
if (hasFeaturedDemo) {
  effectiveLimits['Standard'] = 5;
}

// ── If booking a Featured Demo and Standard is already over the new limit ─────
if (
  newEntry.placementType === 'Featured Demo' &&
  placementCounts['Standard'] > effectiveLimits['Standard']
) {
  return [
    {
      json: {
        status: 409,
        message: `Unfortunately, this Featured Demo slot is no longer available because Standard placements have already exceeded the allowed limit.`,
        newsletter: newsletterName,
        userInput: userInput,
        existingBookings: matchedBookings,
        reason: 'featured_demo_conflicts_with_standard_cap',
        placementType: newEntry.placementType,
        currentCount: placementCounts['Featured Demo'],
        limit: effectiveLimits['Featured Demo'],
      }
    }
  ];
}

// ── Total booking count (existing + this new one) ─────────────────────────────
const totalExisting = existingBookings.length;
const totalAfter = totalExisting + 1;

// ── Check total cap ───────────────────────────────────────────────────────────
if (totalAfter > MAX_TOTAL) {
  return [
    {
      json: {
        status: 409,
        message: `Unfortunately, this ${newEntry.placementType} slot is no longer available. The total bookings for ${newsletterName} have reached the maximum of ${MAX_TOTAL} (${totalAfter} bookings).`,
        newsletter: newsletterName,
        userInput: userInput,
        existingBookings: matchedBookings,
        reason: 'total_cap_exceeded',
      }
    }
  ];
}

// ── Check per-placement cap ───────────────────────────────────────────────────
const placementType = newEntry.placementType;
const currentCount = placementCounts[placementType] || 0;
const limit = effectiveLimits[placementType];

if (limit !== undefined && currentCount >= limit) {
  return [
    {
      json: {
        status: 409,
       message: `Unfortunately, this ${placementType} slot is fully booked. ${newsletterName} already has ${currentCount} bookings, which meets the maximum limit of ${limit}.`,
        newsletter: newsletterName,
        userInput: userInput,
        existingBookings: matchedBookings,
        reason: 'placement_cap_exceeded',
        placementType: placementType,
        currentCount: currentCount,
        limit: limit,
      }
    }
  ];
}

// ── Success ───────────────────────────────────────────────────────────────────
return [
  {
    json: {
      status: 200,
      message: 'You’ve successfully booked the Influencer newsletter',
      newsletter: newsletterName,
      userInput: userInput,
      summary: {
        placementType: placementType,
        newTotalBookings: totalAfter,
        placementCountAfter: currentCount + 1,
        placementLimit: limit,
        featuredDemoRuleApplied: hasFeaturedDemo,
        effectiveLimits: effectiveLimits,
      }
    }
  }
];

const userInputItems = $('INFLUENCER: CHECK MODE').all();
const previousNodeItems = $input.all();

// ── Extract data ──────────────────────────────────────────────────────────────
const userInput = userInputItems[0].json;
const entries = userInput.entries || [];

// ── Placement limits ──────────────────────────────────────────────────────────
const LIMITS = {
  'Featured': 1,
  'Featured Demo': 1,
  'Promoted': 6,
  'Standard': 6,
};
const MAX_TOTAL = 13;

// ── Parse existing bookings ───────────────────────────────────────────────────
const isEmpty =
  previousNodeItems.length === 0 ||
  (previousNodeItems.length === 1 && Object.keys(previousNodeItems[0].json).length === 0);

const existingBookings = isEmpty ? [] : previousNodeItems.map(item => item.json);

// ── Normalize date: "2026-03-20" or "March 20 2026" → "March 20 2026" ────────
function normalizeDate(dateStr) {
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })
          .replace(',', '');
}

// ── Group existing bookings by date ──────────────────────────────────────────
const existingByDate = {};
for (const b of existingBookings) {
  const key = b.date_schedule;
  if (!existingByDate[key]) existingByDate[key] = [];
  existingByDate[key].push(b);
}

// ── Simulate slot consumption as we go ───────────────────────────────────────
const pendingByDate = {};
for (const [date, bookings] of Object.entries(existingByDate)) {
  pendingByDate[date] = [...bookings];
}

// ── Process each entry ────────────────────────────────────────────────────────
const accepted = [];
const rejected = [];

for (const entry of entries) {
  const entryDate = normalizeDate(entry.date);
  const placementType = entry.placementType;
  const dateBookings = pendingByDate[entryDate] || [];

  // Check total cap for this date
  if (dateBookings.length >= MAX_TOTAL) {
    rejected.push({
      id: entry.id,
      date: entryDate,
      productName: entry.productName,
      placementType,
      reason: `${entryDate} is fully booked (max ${MAX_TOTAL} total)`,
    });
    continue;
  }

  // ── Featured Demo ↔ Standard mutual constraint ────────────────────────────
  const alreadyHasFeaturedDemo =
    dateBookings.some(b => b.newsletter_placement === 'Featured Demo');

  const currentEntryIsFeaturedDemo = placementType === 'Featured Demo';

  const hasFeaturedDemo = alreadyHasFeaturedDemo || currentEntryIsFeaturedDemo;

  const effectiveLimits = { ...LIMITS };
  if (hasFeaturedDemo) effectiveLimits['Standard'] = 5;

  // If booking a Featured Demo, check existing Standard count doesn't exceed 5
  if (currentEntryIsFeaturedDemo) {
    const standardCount = dateBookings.filter(
      b => b.newsletter_placement === 'Standard'
    ).length;
    if (standardCount > 5) {
      rejected.push({
        id: entry.id,
        date: entryDate,
        productName: entry.productName,
        placementType,
        reason: `Cannot book Featured Demo on ${entryDate}: Standard slots (${standardCount}) exceed the 5-slot limit that Featured Demo requires`,
      });
      continue;
    }
  }

  // Check per-placement cap for this date
  const placementCount = dateBookings.filter(
    b => b.newsletter_placement === placementType
  ).length;
  const limit = effectiveLimits[placementType];

  if (limit !== undefined && placementCount >= limit) {
    rejected.push({
      id: entry.id,
      date: entryDate,
      productName: entry.productName,
      placementType,
      reason: `${placementType} on ${entryDate} is fully booked (${placementCount}/${limit})`,
    });
    continue;
  }

  // Accept — consume the slot
  if (!pendingByDate[entryDate]) pendingByDate[entryDate] = [];
  pendingByDate[entryDate].push({ newsletter_placement: placementType });

  accepted.push({
    id: entry.id,
    date: entryDate,
    productName: entry.productName,
    placementType,
    organizationLink: entry.organizationLink,
    productLink: entry.productLink,
    segment: entry.segment,
    purchaseType: entry.purchaseType,
    notes: entry.notes,
    slot: `${placementCount + 1}/${limit}`,
  });
}

// ── Return ────────────────────────────────────────────────────────────────────
const allAccepted = rejected.length === 0;
const allRejected = accepted.length === 0;

const rejectedPlacements = new Set(rejected.map(r => r.placementType));
const filteredExistingBookings = existingBookings.filter(b =>
  rejectedPlacements.has(b.newsletter_placement)
);

return [
  {
    json: {
      status: allAccepted ? 200 : allRejected ? 409 : 207,
      message: allAccepted
        ? 'All entries for the Influencer newsletter have been successfully booked'
        : allRejected
        ? 'All entries are currently unavailable'
        : `Partial: ${accepted.length} booked, ${rejected.length} rejected`,
      userInput,
      accepted,
      rejected,
      ...( !allAccepted && { existingBookings: filteredExistingBookings } ),
    },
  },
];

