const userInputItems = $('BOTH: USER INPUT').all();
const previousNodeItems = $input.all();

// ── Extract data ──────────────────────────────────────────────────────────────
const userInput = userInputItems[0].json;
const entries = userInput.entries || [];
const newEntry = entries[0]; // single submission mode
const newsletterName = 'Both';
const placementType = newEntry.placementType;

// ── Placement limits ──────────────────────────────────────────────────────────
const LIMITS = {
  Influencer: {
    'Featured':      1,
    'Featured Demo': 1,
    'Promoted':      6,
    'Standard':      6,
  },
  Press: {
    'Featured':      1,
    'Featured Demo': 1,
    'Promoted':      4,
    'Standard':      8,
  },
};
const MAX_TOTAL = 13;

// ── Parse existing bookings ───────────────────────────────────────────────────
const isEmpty =
  previousNodeItems.length === 0 ||
  (previousNodeItems.length === 1 && Object.keys(previousNodeItems[0].json).length === 0);

const existingBookings = isEmpty ? [] : previousNodeItems.map(item => item.json);

// ── Split bookings by newsletter_type ────────────────────────────────────────
const influencerBookings = existingBookings.filter(b => b.newsletter_type === 'Influencer');
const pressBookings      = existingBookings.filter(b => b.newsletter_type === 'Press');

// ── Count per placement per type ─────────────────────────────────────────────
function countPlacements(bookings) {
  const counts = { 'Featured': 0, 'Featured Demo': 0, 'Promoted': 0, 'Standard': 0 };
  for (const b of bookings) {
    if (b.newsletter_placement in counts) counts[b.newsletter_placement]++;
  }
  return counts;
}

const influencerCounts = countPlacements(influencerBookings);
const pressCounts      = countPlacements(pressBookings);

// ── Apply Featured Demo rule per type ─────────────────────────────────────────
// If a Featured Demo exists (or is being booked now), Standard max drops by 1
function getEffectiveLimits(baseLimits, counts, incomingPlacementType) {
  const effective = { ...baseLimits };
  const hasFeaturedDemo =
    counts['Featured Demo'] > 0 || incomingPlacementType === 'Featured Demo';
  if (hasFeaturedDemo) effective['Standard'] = baseLimits['Standard'] - 1;
  return { effective, hasFeaturedDemo };
}

const {
  effective: effInfluencer,
  hasFeaturedDemo: fdInfluencer,
} = getEffectiveLimits(LIMITS.Influencer, influencerCounts, placementType);

const {
  effective: effPress,
  hasFeaturedDemo: fdPress,
} = getEffectiveLimits(LIMITS.Press, pressCounts, placementType);

// ── Helper: build 409 response ────────────────────────────────────────────────
function reject409(reason, message, extra = {}) {
  return [
    {
      json: {
        status: 409,
        message,
        newsletter: newsletterName,
        userInput,
        existingBookings,
        reason,
        placementType,
        ...extra,
      },
    },
  ];
}

// ── Check: Featured Demo conflicts with already-exceeded Standard cap ─────────
if (placementType === 'Featured Demo') {
  const influencerStandardFull = influencerCounts['Standard'] > effInfluencer['Standard'];
  const pressStandardFull      = pressCounts['Standard'] > effPress['Standard'];

  if (influencerStandardFull && pressStandardFull) {
    return reject409(
      'featured_demo_conflicts_with_standard_cap_both',
      `Unfortunately, this Featured Demo slot is no longer available for both Influencer and Press because Standard placements have already exceeded the allowed limit on both.`,
      {
        influencer: {
          currentStandardCount: influencerCounts['Standard'],
          standardLimitAfterFeaturedDemo: effInfluencer['Standard'],
        },
        press: {
          currentStandardCount: pressCounts['Standard'],
          standardLimitAfterFeaturedDemo: effPress['Standard'],
        },
      }
    );
  }

  if (influencerStandardFull) {
    return reject409(
      'featured_demo_conflicts_with_standard_cap',
      `Unfortunately, this Featured Demo slot is no longer available for Influencer because Standard placements have already exceeded the allowed limit.`,
      {
        conflictingType: 'Influencer',
        currentStandardCount: influencerCounts['Standard'],
        standardLimitAfterFeaturedDemo: effInfluencer['Standard'],
      }
    );
  }

  if (pressStandardFull) {
    return reject409(
      'featured_demo_conflicts_with_standard_cap',
      `Unfortunately, this Featured Demo slot is no longer available for Press because Standard placements have already exceeded the allowed limit.`,
      {
        conflictingType: 'Press',
        currentStandardCount: pressCounts['Standard'],
        standardLimitAfterFeaturedDemo: effPress['Standard'],
      }
    );
  }
}

// ── Check total cap ───────────────────────────────────────────────────────────
const totalExisting = existingBookings.length;
const totalAfter    = totalExisting + 1;

if (totalAfter > MAX_TOTAL) {
  return reject409(
    'total_cap_exceeded',
    `Unfortunately, this ${placementType} slot is no longer available.`,
    { currentTotal: totalExisting, maxTotal: MAX_TOTAL }
  );
}

// ── Check per-placement cap for Influencer & Press ───────────────────────────
const influencerCurrent = influencerCounts[placementType] || 0;
const influencerLimit   = effInfluencer[placementType];
const pressCurrent      = pressCounts[placementType] || 0;
const pressLimit        = effPress[placementType];

const influencerFull = influencerLimit !== undefined && influencerCurrent >= influencerLimit;
const pressFull      = pressLimit !== undefined && pressCurrent >= pressLimit;

if (influencerFull && pressFull) {
  return reject409(
    'placement_cap_exceeded_both',
    `Unfortunately, this ${placementType} slot is fully booked for both Influencer and Press.`,
    {
      influencer: { currentCount: influencerCurrent, limit: influencerLimit },
      press:      { currentCount: pressCurrent,      limit: pressLimit },
    }
  );
}

if (influencerFull) {
  return reject409(
    'placement_cap_exceeded_influencer',
    `Unfortunately, this ${placementType} slot is fully booked for Influencer.`,
    { conflictingType: 'Influencer', currentCount: influencerCurrent, limit: influencerLimit }
  );
}

if (pressFull) {
  return reject409(
    'placement_cap_exceeded_press',
    `Unfortunately, this ${placementType} slot is fully booked for Press.`,
    { conflictingType: 'Press', currentCount: pressCurrent, limit: pressLimit }
  );
}

// ── Success ───────────────────────────────────────────────────────────────────
return [
  {
    json: {
      status: 200,
      message: `You've successfully booked the newsletter for Influencer and Press`,
      newsletter: newsletterName,
      userInput,
      summary: {
        placementType,
        newTotalBookings: totalAfter,
        influencer: {
          placementCountAfter: influencerCurrent + 1,
          placementLimit: influencerLimit,
          featuredDemoRuleApplied: fdInfluencer,
          effectiveLimits: effInfluencer,
        },
        press: {
          placementCountAfter: pressCurrent + 1,
          placementLimit: pressLimit,
          featuredDemoRuleApplied: fdPress,
          effectiveLimits: effPress,
        },
      },
    },
  },
];
